SELECT u.username, um.tweet_count, um.average_likes_per_tweet
FROM users u
INNER JOIN user_metrics um ON u.user_id = um.user_id;

SELECT url, display_text
FROM tweet_links
WHERE tweet_id = 950908942003113991;

SELECT name, tweet_count 
FROM users 
WHERE location = 'Anna Maria, FL';

SELECT username
FROM users
WHERE followers_count = (SELECT MAX(followers_count) FROM users);
